const altitude = Number(msg.payload?.takeoff_alt_m || 20);
const radius = Number(msg.payload?.circle_radius_m || 25);

msg.topic = "mavlink-ai/example/onboard-companion-storyboard";
msg.payload = {
    dry_run: true,
    sends_mavlink: false,
    onboard_device: "Raspberry Pi / companion computer",
    note: "Debug-only storyboard. This flow does not contain a MAVLink output node.",
    routine: [
        { order: 1, phase: "takeoff", description: `take off to ${altitude} m` },
        { order: 2, phase: "circle", description: `fly one circle at roughly ${radius} m radius` },
        { order: 3, phase: "barrel_roll", description: "barrel roll phase marker" },
        { order: 4, phase: "yaw_360", description: "perform a 360 turn/spin marker" },
        { order: 5, phase: "tilt_left", description: "tilt left marker" },
        { order: 6, phase: "tilt_right", description: "tilt right marker" },
        { order: 7, phase: "tilt_front", description: "tilt front marker" },
        { order: 8, phase: "tilt_back", description: "tilt back marker" },
        { order: 9, phase: "return", description: "return to launch/home marker" },
        { order: 10, phase: "land", description: "land marker" }
    ]
};

node.status({ fill: "blue", shape: "dot", text: "storyboard emitted" });
return msg;
